// src/components/DeckBuilder.js
import React, { useState } from 'react';

const mockArticles = [
  { id: 1, title: 'AI Trends 2025', summary: 'A review of expected trends.' },
  { id: 2, title: 'Generative Models in Healthcare', summary: 'Applications in diagnostics and prediction.' },
  { id: 3, title: 'Transformer Architectures', summary: 'Comparison of variants and use cases.' },
];

const DeckBuilder = () => {
  const [selectedIds, setSelectedIds] = useState([]);

  const toggleSelect = (id) => {
    setSelectedIds(prev =>
      prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
    );
  };

  const exportCSV = () => {
    const csvContent = [
      ['Title', 'Summary'],
      ...mockArticles.filter(a => selectedIds.includes(a.id)).map(a => [a.title, a.summary])
    ]
      .map(row => row.join(','))
      .join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = 'research_deck.csv';
    link.click();
  };

  return (
    <div>
      <h2 className="text-xl font-bold mb-4">Deck Builder</h2>
      <table className="w-full bg-white shadow rounded mb-4">
        <thead className="bg-gray-100">
          <tr>
            <th className="p-2">Select</th>
            <th className="p-2">Title</th>
            <th className="p-2">Summary</th>
          </tr>
        </thead>
        <tbody>
          {mockArticles.map(article => (
            <tr key={article.id}>
              <td className="p-2 text-center">
                <input type="checkbox" checked={selectedIds.includes(article.id)} onChange={() => toggleSelect(article.id)} />
              </td>
              <td className="p-2">{article.title}</td>
              <td className="p-2">{article.summary}</td>
            </tr>
          ))}
        </tbody>
      </table>
      <button className="bg-purple-600 text-white px-4 py-2 rounded" onClick={exportCSV}>Export to CSV</button>
    </div>
  );
};

export default DeckBuilder;
